{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式キックオフおよび正式発足を承認した",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "主要画面の応答時間目標を通信込みで1.2秒以内とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標時期を2026年10月15日に変更する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "週次定例会議を毎週水曜日10時から1時間枠で開催し、各部署から最低1名参加とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "現場ヒアリングを早期に実施し、生産管理部を窓口として対象部署リストを作成して進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "第1フェーズではマスタ系データのみを移行し、トランザクション履歴は旧システムを参照用として残す",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "検証環境用サーバは本番構成を簡略化した縮小構成とし、現行6台をベースに倍から3台削る考え方で調達を進める",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D8",
      "content": "認証およびマスタ配信基盤はサクラ商事株式会社の基盤を共同利用する第3案で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "認証基盤の共同利用に関する費用按分方法はサクラ商事株式会社側と協議して決定する",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D10",
      "content": "開発用外部ライセンス費用は2025年秋の見積を使わず再見積を取得した上で最終確定する",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D11",
      "content": "マスタ配信の頻度など詳細設計は今後別途検討するが、頻度は1日1回より多くする方向で検討する",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D12",
      "content": "開発用外部ライセンスは開発者8名が3か月連続で利用する前提でコストを見込む",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D13",
      "content": "認証基盤が自前構築案となった場合は追加見積と予算調整を別途行う",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D14",
      "content": "移行方式は拠点を複数グループに分けて順次切り替える段階移行（B案）で実施する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D15",
      "content": "各拠点のシステム切替作業は土曜深夜から日曜にかけて実施し、日曜を予備日として確保する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D16",
      "content": "負荷テストの合格基準は社内ネットワーク側測定点においてピーク想定時にも主要画面応答時間1.2秒以内を満たすこととする",
      "decided_by": "白鳥 千夏"
    },
    {
      "id": "D17",
      "content": "負荷テストは素の性能計測とピーク時シナリオ実行の二段構えで実施し、結合テスト完了後とシステムテスト後半の2回行う",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D18",
      "content": "移行テストおよび負荷テストはシステムテストと別立ての工程として計画する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D19",
      "content": "負荷テスト専用に本番相当に近い独立した縮小構成環境を用意し、他作業と共用しない",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D20",
      "content": "現行システムのテストケースは新システム向け転用前に棚卸しし、生きているもの・破棄・要修正に三分類する",
      "decided_by": "白鳥 千夏"
    },
    {
      "id": "D21",
      "content": "移行リハーサル時は切り戻し手順も含めた手順書に基づいて実施し、手順書はインフラ側で作成しQAがレビューする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D22",
      "content": "障害発生時の一次受け窓口を情報システム部からQAチームへ変更し、QAが一次切り分け後に情シスやインフラへエスカレーションする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D23",
      "content": "新システムのユーザー権限ロールは当面現行ロール定義を流用し、新規ロール設計は稼働後の運用改善タスクとして別途実施する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D24",
      "content": "ベンダー選定は納期と予算の理由によりハギワラ技研株式会社とツヅキシステム株式会社を見送り、コマツバ・ソリューションズ株式会社を前提に進める",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D25",
      "content": "稟議上のコスト増は現在の予算枠の一割強以内に収め、超過が見込まれる場合は稟議の出し直しを回避する方向で調整する",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D26",
      "content": "旧システムは履歴参照用途として稼働を継続し、監査対応上も参照可能状態を維持する",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D27",
      "content": "サクラ商事株式会社との認証基盤共同利用ではデータは論理的に分離し混在させない前提とする",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D28",
      "content": "現場向けシステム説明会を拠点ごとの繁忙を考慮し複数回に分けて開催する",
      "decided_by": "桐生 遥"
    }
  ],
